public class Main {

    // Returns new balance — does not modify original directly
    public static double deposit(double balance, double amount) {
        if (amount <= 0) return balance;  // invalid amount
        return balance + amount;
    }

    public static double withdraw(double balance, double amount) {
        if (amount <= 0 || amount > balance) return balance;
        return balance - amount;
    }

    // Returns two values as an array: {min, max}
    public static double[] findMinMax(double[] values) {
        double min = values[0], max = values[0];
        for (double v : values) {
            if (v < min) min = v;
            if (v > max) max = v;
        }
        return new double[]{min, max};
    }

    public static void main(String[] args) {

        // Pass-by-value demo
        double balance = 5000.0;
        balance = deposit(balance, 2000.0);   // must re-assign
        balance = withdraw(balance, 1500.0);
        System.out.printf("Balance: Rs %.2f%n", balance);

        // Block scope: i is only visible inside the loop
        for (int i = 0; i < 3; i++) {
            double bonus = 100.0 * (i + 1);   // bonus is block-scoped
            System.out.println("Bonus: " + bonus);
        }
        // i and bonus are not accessible here

        // Multiple return values via array
        double[] history  = {3200.0, 4800.0, 1500.0, 9100.0, 600.0};
        double[] minMax   = findMinMax(history);
        System.out.printf("Min: Rs %.0f, Max: Rs %.0f%n",
                          minMax[0], minMax[1]);
    }
}

