public class Main {

    public static double[] getStats(int[] marks) {
        double total = 0;
        int min = marks[0], max = marks[0];

        for (int m : marks) {
            total += m;
            if (m < min) min = m;
            if (m > max) max = m;
        }

        double avg = total / marks.length;
        return new double[]{avg, min, max};
    }

    public static void main(String[] args) {
        int[] marks = {72, 88, 95, 61, 83};
        double[] stats = getStats(marks);

        System.out.printf("Average: %.1f%n", stats[0]);
        System.out.printf("Min: %d%n", (int) stats[1]);
        System.out.printf("Max: %d%n", (int) stats[2]);
    }
}
